#include<bits/stdc++.h>
using namespace std;
int fa[200010][21],a[200010],n,k,lg[200010],d[200010];
vector<int> mp[200010],v[200010];
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int dist(int x,int y)
{
    return d[x]+d[y]-d[lca(x,y)]*2;
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(int i=1;i<=n;i++)
    {
        int p;
        scanf("%d%d",&a[i],&p);
        v[a[i]].push_back(i);
        mp[p].push_back(i);
        mp[i].push_back(p);
    }
    dfs(1);
    for(int i=1;i<=k;i++)
    {
        int max1=0,max2=0,max3=0;
        for(int j:v[i])
        {
            if(d[j]>max1)
            {
                max1=d[j];
                max2=j;
            }
        }
        for(int j:v[i])
        {
            max3=max(max3,dist(max2,j));
        }
        printf("%d\n",max3);
    }
    return 0;
}
